import{_ as o,o as a,c as t,a3 as i}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Namespace clore::net::openai::protocol::detail","description":"clore::net::openai::protocol::detail 命名空间封装了 OpenAI 协议序列化与解析的底层实现细节。其中提供了 serialize_* 系列函数（如 serialize_message, serialize_tool_definition, serialize_tool_choice, serialize_response_format）将内部数据结构写入 JSON 对象或数组；以及 parse_* 系列函数（如 parse_tool_calls, parse_content_parts）从 JSON 数组读取并解析协议实体。所有函数均接受 json::Array 或 json::Object 引用作为输出/输入，并以整型返回码指示操作成功或错误状态。该命名空间在架构上位于协议层的最内层，专供协议模块内部调用，外部代码不应直接依赖这些函数。","frontmatter":{"title":"Namespace clore::net::openai::protocol::detail","description":"clore::net::openai::protocol::detail 命名空间封装了 OpenAI 协议序列化与解析的底层实现细节。其中提供了 serialize_* 系列函数（如 serialize_message, serialize_tool_definition, serialize_tool_choice, serialize_response_format）将内部数据结构写入 JSON 对象或数组；以及 parse_* 系列函数（如 parse_tool_calls, parse_content_parts）从 JSON 数组读取并解析协议实体。所有函数均接受 json::Array 或 json::Object 引用作为输出/输入，并以整型返回码指示操作成功或错误状态。该命名空间在架构上位于协议层的最内层，专供协议模块内部调用，外部代码不应直接依赖这些函数。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/openai/protocol/detail/index.md","filePath":"zh/clore/namespaces/clore/net/openai/protocol/detail/index.md"}'),l={name:"zh/clore/namespaces/clore/net/openai/protocol/detail/index.md"};function n(r,e,c,p,d,s){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="namespace-clore-net-openai-protocol-detail" tabindex="-1">Namespace <code>clore::net::openai::protocol::detail</code> <a class="header-anchor" href="#namespace-clore-net-openai-protocol-detail" aria-label="Permalink to &quot;Namespace `clore::net::openai::protocol::detail`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::net::openai::protocol::detail</code> 命名空间封装了 <code>OpenAI</code> 协议序列化与解析的底层实现细节。其中提供了 <code>serialize_*</code> 系列函数（如 <code>serialize_message</code>, <code>serialize_tool_definition</code>, <code>serialize_tool_choice</code>, <code>serialize_response_format</code>）将内部数据结构写入 JSON 对象或数组；以及 <code>parse_*</code> 系列函数（如 <code>parse_tool_calls</code>, <code>parse_content_parts</code>）从 JSON 数组读取并解析协议实体。所有函数均接受 <code>json::Array</code> 或 <code>json::Object</code> 引用作为输出/输入，并以整型返回码指示操作成功或错误状态。该命名空间在架构上位于协议层的最内层，专供协议模块内部调用，外部代码不应直接依赖这些函数。</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-openai-protocol-detail-parse-content-parts" tabindex="-1"><code>clore::net::openai::protocol::detail::parse_content_parts</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-parse-content-parts" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::parse_content_parts`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:288</code></p><p>Definition: <code>network/openai.cppm:288</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::openai::protocol::detail::parse_content_parts</code> 接受一个常量 <code>json::Array</code> 引用，解析其中的内容部分（content parts），并返回一个整数。调用者应保证传入的数组符合 <code>OpenAI</code> 协议中内容片段的格式；返回值的含义由具体实现决定，通常用于指示解析是否成功或已处理的项目数量。该函数位于协议细节命名空间内，仅供内部使用，外部代码不应直接调用。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called when parsing chat completion response content from <code>OpenAI</code> API</li></ul><h3 id="clore-net-openai-protocol-detail-parse-tool-calls" tabindex="-1"><code>clore::net::openai::protocol::detail::parse_tool_calls</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-parse-tool-calls" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::parse_tool_calls`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:369</code></p><p>Definition: <code>network/openai.cppm:369</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p><code>parse_tool_calls</code> 函数接受一个 <code>const json::Array &amp;</code> 参数，该参数应包含工具调用数据。调用者负责提供符合预期格式的有效 JSON 数组。函数返回一个整型值：零表示解析成功，非零表示解析过程中发生了错误。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to parse <code>tool_calls</code> from an <code>OpenAI</code> API response</li><li>used in response deserialization pipeline</li></ul><h3 id="clore-net-openai-protocol-detail-serialize-message" tabindex="-1"><code>clore::net::openai::protocol::detail::serialize_message</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-serialize-message" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::serialize_message`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:27</code></p><p>Definition: <code>network/openai.cppm:27</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p>函数 <code>clore::net::openai::protocol::detail::serialize_message</code> 负责将一条消息序列化到提供的 <code>json::Array</code> 引用中。它接受一个可变的 <code>json::Array &amp;</code> 作为输出目标以及一个 <code>const int &amp;</code> 参数（表示消息标识符）。返回一个 <code>int</code> 值：成功时返回零，出错时返回非零错误码。调用者必须确保传入的数组引用有效且整数参数正确标识待序列化的消息；函数不管理数组的生命周期，调用者需保证数组在调用后仍可用。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为 <code>OpenAI</code> 协议消息序列化的一部分，用于将消息列表转换为 JSON 请求体</li></ul><h3 id="clore-net-openai-protocol-detail-serialize-response-format" tabindex="-1"><code>clore::net::openai::protocol::detail::serialize_response_format</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-serialize-response-format" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::serialize_response_format`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:209</code></p><p>Definition: <code>network/openai.cppm:209</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p>将给定的响应格式标识符序列化到指定的 <code>json::Object</code> 中。函数接受一个可变的 <code>json::Object &amp;</code> 作为输出目标，以及一个 <code>const int &amp;</code> 指定要序列化的格式。返回值是一个 <code>int</code>，指示操作成功或失败的状态码。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called during serialization of <code>OpenAI</code> API request body</li><li>Used to set the response format for chat completions requests</li></ul><h3 id="clore-net-openai-protocol-detail-serialize-tool-choice" tabindex="-1"><code>clore::net::openai::protocol::detail::serialize_tool_choice</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-serialize-tool-choice" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::serialize_tool_choice`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:167</code></p><p>Definition: <code>network/openai.cppm:167</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::openai::protocol::detail::serialize_tool_choice</code> 将工具选择配置写入给定的 JSON 对象。它接受一个可变的 <code>json::Object</code> 引用和一个 <code>const int &amp;</code>（表示工具选择的整数值），并在该对象中填充对应的字段。</p><p>调用者负责提供一个可修改且初始状态正确的 <code>json::Object</code>，函数会直接修改此对象。函数返回一个整型值，非零通常表示错误；调用者应当检查返回值以确保序列化成功。该函数不负责验证工具选择值本身的语义有效性，仅执行写入操作。</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called during serialization of <code>OpenAI</code> API request bodies</li><li>Used to set the <code>tool_choice</code> field in a JSON object</li></ul><h3 id="clore-net-openai-protocol-detail-serialize-tool-definition" tabindex="-1"><code>clore::net::openai::protocol::detail::serialize_tool_definition</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-serialize-tool-definition" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::serialize_tool_definition`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:248</code></p><p>Definition: <code>network/openai.cppm:248</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p>函数 <code>clore::net::openai::protocol::detail::serialize_tool_definition</code> 将给定工具定义的序列化表示写入到 <code>json::Array</code> 中。调用者提供目标数组以及一个 <code>int</code> 值，该值标识要序列化的工具定义。函数返回一个 <code>int</code>，指示操作结果（例如成功或失败状态），具体的返回码及语义由调用者根据上下文确定。该函数是底层序列化基础设施的一部分，不应直接由用户代码调用。</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called when constructing tool definitions for <code>OpenAI</code> API requests during serialization.</li></ul><h3 id="clore-net-openai-protocol-detail-validate-request" tabindex="-1"><code>clore::net::openai::protocol::detail::validate_request</code> <a class="header-anchor" href="#clore-net-openai-protocol-detail-validate-request" aria-label="Permalink to &quot;`clore::net::openai::protocol::detail::validate_request`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:23</code></p><p>Definition: <code>network/openai.cppm:23</code></p><p>Implementation: <a href="./../../../../../../modules/openai/"><code>Module openai</code></a></p><p>函数 <code>clore::net::openai::protocol::detail::validate_request</code> 对以 <code>const int &amp;</code> 传入的请求标识符所指向的数据执行验证，确认其符合预期的协议规范。返回值（类型为 <code>int</code>）指示验证结果，通常零值表示成功，非零值表示特定的错误条件。</p><p>调用者有责任确保提供的请求标识符对应一个完整且已正确初始化的请求对象。本函数不修改参数，也不承担所有权转移；调用者应在调用前确认请求的有效性，并根据返回值判断是否继续后续处理。</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Validation of <code>CompletionRequest</code> before further processing</li><li>Called by <code>OpenAI</code> protocol layer</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net::openai::protocol</a></li></ul>',57)])])}const m=o(l,[["render",n]]);export{u as __pageData,m as default};
